import { compose, pluck, sum } from '../pkg/rambda.js';
import { range } from './array.functions.js';
/**
 * Can be used for any roll
 */

export const countSuccesses = roll => roll < 6 ? 0 : Math.floor(roll / 2) - 2; // https://developer.mozilla.org/en-US/docs/Web/JavaScript/Reference/Global_Objects/Math/random#Getting_a_random_integer_between_two_values_inclusive

export function getRandomInt(min = 1, max = 6) {
  min = Math.ceil(min);
  max = Math.floor(max); //The maximum is inclusive and the minimum is inclusive

  return Math.floor(Math.random() * (max - min + 1)) + min;
}
export const rollD2 = () => getRandomInt(1, 2);
export const rollD3 = () => getRandomInt(1, 3);
export const rollD4 = () => getRandomInt(1, 4);
export const rollD6 = () => getRandomInt(1, 6);
export const rollD8 = () => getRandomInt(1, 8);
export const rollD66 = () => {
  const tens = rollD6() * 10;
  const ones = rollD6();
  return tens + ones;
};
export const parseD6String = str => {
  const parts = str.split('D');

  if (parts[0] === '') {
    return 1;
  }

  return parseInt(parts[0], 10);
};
export const parseChoiceString = str => str.split('|').map(c => c.split('^').map(a => parseInt(a, 10) ?? 1)).map(cs => range(cs.length === 2 ? cs[1] : 1).map(_ => cs[0])).flat();
export const choose = arr => arr[getRandomInt(0, arr.length - 1)];
export const chooseFromChoiceString = compose(choose, parseChoiceString);
export const weightedRandomConsume = probabilities => {
  const totalWeight = sum(pluck('weight', probabilities));
  const randomInt = getRandomInt(0, totalWeight);
  const chosen = probabilities.reduce((acc, cur, index) => {
    if (acc.done > -1) {
      return acc;
    }

    const newLeft = acc.left - cur.weight;

    if (newLeft <= 0) {
      return {
        left: 0,
        done: index,
        data: cur
      };
    }

    return { ...acc,
      left: newLeft
    };
  }, {
    left: randomInt,
    done: -1,
    data: {
      weight: 0
    }
  });
  const rest = probabilities.filter((_val, index) => index !== chosen.done);
  return [chosen.data, rest];
};
export const weightedRandom = probabilities => weightedRandomConsume(probabilities)[0];